const bcrypt = require('bcrypt');

async function hashPassword(password) {
    try{
        const saltRounds = 10;  //you can increase it for more secure but also increase the time complexity
        const hashedPassword = await bcrypt.hash(password, saltRounds);
         return hashedPassword;  
     }catch (error){
       console.log("Error:", error);
    }
}
module.exports= hashPassword;  // exporting the function to use in another file